void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 center = vec2(.5,.5);

    vec2 light1 = vec2(sin(uTime*1.2+50.0)*1.0 + cos(uTime*0.4+10.0)*0.6,sin(uTime*1.2+100.0)*1.6 + cos(uTime*0.2+20.0)*-0.2)*0.2+center;
    vec3 lightColor1 = vec3(1.0, 0.3, 0.3);

    vec2 light2 = vec2(sin(uTime+3.0)*-2.0,cos(uTime+7.0)*2.0)*0.2+center;
    vec3 lightColor2 = vec3(0.3, 1.0, 0.3);

    vec2 light3 = vec2(sin(uTime+3.0)*2.0,cos(uTime+14.0)*-2.0)*0.2+center;
    vec3 lightColor3 = vec3(0.3, 0.3, 1.0);


    float cloudIntensity1 = 0.7*(1.0-(2.5*distance(vUv, light1)));
    float lighIntensity1 = 1.0/(100.0*distance(vUv,light1));

    float cloudIntensity2 = 0.7*(1.0-(2.5*distance(vUv, light2)));
    float lighIntensity2 = 1.0/(100.0*distance(vUv,light2));

    float cloudIntensity3 = 0.7*(1.0-(2.5*distance(vUv, light3)));
    float lighIntensity3 = 1.0/(100.0*distance(vUv,light3));

    ret = texture(sampler_main, vUv).xyz;
	ret += vec4(        cloudIntensity1*clouds(vUv)*lightColor1 + lighIntensity1*lightColor1 +
                     cloudIntensity2*clouds(vUv)*lightColor2 + lighIntensity2*lightColor2 +
                     cloudIntensity3*clouds(vUv)*lightColor3 + lighIntensity3*lightColor3 ,
                     float(1));

  fragColor = ret;
}
